24	// SegmentStyle the style of segment, for more information, see the constants
25	type SegmentStyle string
26	
27	func (s *SegmentStyle) resolve(context any) SegmentStyle {
28		value, err := template.Render(string(*s), context)
29	
30		// default to Plain
31		if err != nil || value == "" {
32			return Plain
33		}
34	
35		return SegmentStyle(value)
36	}
