76		InvertPowerline        bool           `json:"invert_powerline,omitempty" toml:"invert_powerline,omitempty" yaml:"invert_powerline,omitempty"`
77		Force                  bool           `json:"force,omitempty" toml:"force,omitempty" yaml:"force,omitempty"`
78		restored               bool           `json:"-" toml:"-" yaml:"-"`
79		Toggled                bool           `json:"toggled,omitempty" toml:"toggled,omitempty" yaml:"toggled,omitempty"`
80		Pending                bool           `json:"-" toml:"-" yaml:"-"`
81		Interactive            bool           `json:"interactive,omitempty" toml:"interactive,omitempty" yaml:"interactive,omitempty"`
82		foregroundResolved     bool
