87	// segmentAlias is used to avoid recursion during unmarshaling
88	type segmentAlias Segment
89	
90	// segmentAux is a helper struct that captures the legacy 'properties' field
91	type segmentAux struct {
92		Properties options.Map `json:"properties,omitempty" yaml:"properties,omitempty" toml:"properties,omitempty"`
93		*segmentAlias
94	}
95	
96	func (segment *Segment) UnmarshalJSON(data []byte) error {
97		aux := &segmentAux{
98			segmentAlias: (*segmentAlias)(segment),
99		}
100	
101		if err := json.Unmarshal(data, aux); err != nil {
102			return err
103		}
104	
105		// Migrate 'properties' to 'options' if present
106		if len(aux.Properties) > 0 && len(segment.Options) == 0 {
107			segment.Options = aux.Properties
108		}
109	
110		return nil
111	}
112	
113	func (segment *Segment) UnmarshalYAML(node *yaml.Node) error {
114		// Decode into a map to handle field renaming
115		var raw map[string]any
116		if err := node.Decode(&raw); err != nil {
117			return err
118		}
119	
120		// If 'properties' exists and 'options' doesn't, rename it
121		if props, hasProps := raw["properties"]; hasProps {
122			if _, hasOptions := raw["options"]; !hasOptions {
123				raw["options"] = props
124				delete(raw, "properties")
125			}
126		}
127	
128		// Re-encode and decode into the struct
129		modifiedNode := &yaml.Node{}
130		if err := modifiedNode.Encode(raw); err != nil {
131			return err
132		}
133	
134		return modifiedNode.Decode((*segmentAlias)(segment))
135	}
136	
137	// MigratePropertiesToOptions migrates the deprecated Properties field to Options.
138	// This is needed for TOML configs since go-toml/v2 doesn't support custom unmarshalers.
139	func (segment *Segment) MigratePropertiesToOptions() {
140		if len(segment.Properties) > 0 && len(segment.Options) == 0 {
141			segment.Options = segment.Properties
142			segment.Properties = nil
143		}
144	}
145	
146	func (segment *Segment) Name() string {
147		if len(segment.name) != 0 {
148			return segment.name
149		}
150	
151		name := segment.Alias
152		if name == "" {
153			name = c.Title(language.English).String(string(segment.Type))
154		}
155	
156		segment.name = name
157		return name
158	}
159	
160	func (segment *Segment) Execute(env runtime.Environment) {
161		// segment timings for debug purposes
162		var start time.Time
163		if env.Flags().Debug {
164			start = time.Now()
165			segment.NameLength = len(segment.Name())
166			defer func() {
167				segment.Duration = time.Since(start)
168			}()
169		}
170	
171		defer segment.evaluateNeeds()
172	
173		err := segment.MapSegmentWithWriter(env)
174		if err != nil || !segment.shouldIncludeFolder() {
175			return
176		}
177	
178		log.Debugf("segment: %s", segment.Name())
179	
180		if segment.isToggled() {
181			return
182		}
183	
184		if segment.restoreData() {
185			return
186		}
187	
188		cacheRestored := segment.restoreCache()
189		if cacheRestored && !env.Flags().Streaming {
190			return
191		}
192	
193		if shouldHideForWidth(segment.env, segment.MinWidth, segment.MaxWidth) {
194			return
195		}
196	
197		defer func() {
198			if segment.Enabled {
199				template.Cache.AddSegmentData(segment.Name(), segment.writer)
200			}
201		}()
202	
203		// Only segments with a timeout can ever be killed via
204		// KillGoroutineChildren (see prompt/segments.go executeSegmentWithTimeout),
205		// so only those need a Job object to track/terminate their child
206		// processes. Skipping this for the common case (no timeout configured)
207		// avoids two syscalls + a map insert per segment per prompt.
208		if segment.Timeout > 0 {
209			if err := runjobs.CreateJobForGoroutine(segment.Name()); err != nil {
210				log.Errorf("failed to create job for goroutine (segment: %s): %v", segment.Name(), err)
211			}
212	
213			// Release the Job object (Windows) once this goroutine is done
214			// spawning/waiting on children. cmd.Run blocks until its child exits,
215			// so by the time Execute returns - on any path below, including a
216			// panic unwind - no process we intended to keep alive is still
217			// assigned to the job, making it safe to close despite
218			// JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE. If the timeout path already
219			// terminated/closed the job concurrently, this is a no-op; see the
220			// ownership invariant documented on jobs.CloseGoroutineJob.
221			defer runjobs.CloseGoroutineJob()
222		}
223	
224		segment.Enabled = segment.writer.Enabled()
225	}
226	
227	func (segment *Segment) Render(index int, force bool) bool {
228		// Allow pending segments to render (they'll show "..." text)
229		if !segment.Pending && !segment.Enabled && !force {
230			return false
231		}
232	
233		if force {
234			segment.Force = true
235		}
236	
237		// Foreground/background may be overridden directly (e.g. color cycling) between
238		// render passes, so the memoized values must not survive across calls to Render.
239		segment.foregroundResolved = false
240		segment.backgroundResolved = false
241	
242		segment.writer.SetIndex(index)
243	
244		text := segment.string()
245	
246		// Only update Enabled if segment is NOT pending (avoid race with Execute goroutine)
247		if !segment.Pending {
248			segment.Enabled = segment.Force || strings.ContainsFunc(text, func(r rune) bool { return r != ' ' })
249	
250			if !segment.Enabled {
251				template.Cache.RemoveSegmentData(segment.Name())
252				return false
253			}
254		}
255	
256		segment.SetText(text)
257		segment.setCache()
258	
259		// We do this to make `.Text` available for a cross-segment reference in an extra prompt.
260		template.Cache.AddSegmentData(segment.Name(), segment.writer)
261	
262		return true
263	}
264	
265	func (segment *Segment) Text() string {
266		return segment.writer.Text()
267	}
268	
269	func (segment *Segment) SetText(text string) {
270		segment.writer.SetText(text)
271	}
272	
273	func (segment *Segment) ResolveForeground() color.Ansi {
274		if segment.foregroundResolved {
275			return segment.foregroundCache
276		}
277	
278		if len(segment.ForegroundTemplates) != 0 {
279			match := segment.ForegroundTemplates.FirstMatch(segment.writer, segment.Foreground.String())
280			segment.Foreground = color.Ansi(match)
281		}
282	
283		segment.foregroundCache = segment.Foreground
284		segment.foregroundResolved = true
285	
286		return segment.foregroundCache
287	}
288	
289	func (segment *Segment) ResolveBackground() color.Ansi {
290		if segment.backgroundResolved {
291			return segment.backgroundCache
292		}
293	
294		if len(segment.BackgroundTemplates) != 0 {
295			match := segment.BackgroundTemplates.FirstMatch(segment.writer, segment.Background.String())
296			segment.Background = color.Ansi(match)
297		}
298	
299		segment.backgroundCache = segment.Background
300		segment.backgroundResolved = true
301	
302		return segment.backgroundCache
303	}
304	
305	func (segment *Segment) ResolveStyle() SegmentStyle {
306		if len(segment.styleCache) != 0 {
307			return segment.styleCache
308		}
309	
310		segment.styleCache = segment.Style.resolve(segment.writer)
311	
312		return segment.styleCache
313	}
314	
315	func (segment *Segment) IsPowerline() bool {
316		style := segment.ResolveStyle()
317		return style == Powerline || style == Accordion
318	}
319	
320	func (segment *Segment) HasEmptyDiamondAtEnd() bool {
321		if segment.ResolveStyle() != Diamond {
322			return false
323		}
324	
325		return segment.TrailingDiamond == ""
326	}
327	
328	func (segment *Segment) hasCache() bool {
329		return segment.Cache != nil && !segment.Cache.Duration.IsEmpty()
330	}
331	
332	// DataKey returns the identity used to look up segment data: the segment's
333	// alias if set, falling back to its type.
334	func (segment *Segment) DataKey() string {
335		if segment.Alias != "" {
336			return segment.Alias
337		}
338	
339		return string(segment.Type)
340	}
341	
342	// Writer returns the segment's underlying SegmentWriter.
343	func (segment *Segment) Writer() SegmentWriter {
344		return segment.writer
345	}
346	
347	func (segment *Segment) isToggled() bool {
348		togglesMap, OK := cache.Get[map[string]bool](cache.Session, cache.TOGGLECACHE)
349		if !OK || len(togglesMap) == 0 {
350			log.Debug("no toggles found")
351			return false
352		}
353	
354		if togglesMap[segment.DataKey()] {
355			log.Debugf("segment toggled off: %s", segment.Name())
356			return true
357		}
358	
359		return false
360	}
361	
362	func (segment *Segment) restoreCache() bool {
363		if !segment.hasCache() {
364			return false
365		}
366	
367		key, store := segment.cacheKeyAndStore()
368		data, OK := cache.Get[string](store, key)
369		if !OK {
370			log.Debugf("no cache found for segment: %s, key: %s", segment.Name(), key)
371			return false
372		}
373	
374		err := json.Unmarshal([]byte(data), &segment.writer)
375		if err != nil {
376			log.Error(err)
377		}
378	
379		segment.Enabled = true
380		template.Cache.AddSegmentData(segment.Name(), segment.writer)
381	
382		log.Debug("restored segment from cache: ", segment.Name())
383	
384		segment.restored = true
385	
386		return true
387	}
388	
389	// restoreData replays a segment's writer state from the data file supplied via
390	// runtime.Flags.SegmentData, bypassing the real runtime entirely. This lets
391	// segments render from a recorded fixture instead of probing the environment.
392	func (segment *Segment) restoreData() bool {
393		data, OK := segment.env.Flags().SegmentData[segment.DataKey()]
394		if !OK {
395			return false
396		}
397	
398		err := json.Unmarshal(data, &segment.writer)
399		if err != nil {
400			log.Error(err)
401			return false
402		}
403	
404		segment.Enabled = true
405		segment.restored = true
406	
407		template.Cache.AddSegmentData(segment.Name(), segment.writer)
408	
409		log.Debug("restored segment from data: ", segment.Name())
410	
411		return true
412	}
413	
414	func (segment *Segment) setCache() {
415		if segment.restored || !segment.hasCache() {
416			return
417		}
418	
419		// Never cache pending state to avoid polluting cache with incomplete data
420		if segment.Pending {
421			return
422		}
423	
424		data, err := json.Marshal(segment.writer)
425		if err != nil {
426			log.Error(err)
427			return
428		}
429	
430		// TODO: check if we can make segmentwriter a generic Type indicator
431		// that way we can actually get the value straight from cache.Get
432		// and marchalling is obsolete
433		key, store := segment.cacheKeyAndStore()
434		cache.Set(store, key, string(data), segment.Cache.Duration)
435	}
436	
437	func (segment *Segment) cacheKeyAndStore() (string, cache.Store) {
438		format := "segment_cache_%s"
439		switch segment.Cache.Strategy {
440		case Session:
441			return fmt.Sprintf(format, segment.Name()), cache.Session
442		case Device:
443			return fmt.Sprintf(format, segment.Name()), cache.Device
444		case Folder:
445			fallthrough
446		default:
447			return fmt.Sprintf(format, strings.Join([]string{segment.Name(), segment.folderKey()}, "_")), cache.Device
448		}
449	}
450	
451	func (segment *Segment) folderKey() string {
452		key, ok := segment.writer.CacheKey()
453		if !ok {
454			return segment.env.Pwd()
455		}
456	
457		return key
458	}
459	
460	func (segment *Segment) string() string {
461		// Use simple pending text if segment is still pending
462		if segment.Pending {
463			if segment.Placeholder != "" {
464				return segment.Placeholder
465			}
466	
467			return "..."
468		}
469	
470		result := segment.Templates.Resolve(segment.writer, "", segment.TemplatesLogic)
471		if len(result) != 0 {
472			return result
473		}
474	
475		if segment.Template == "" {
476			segment.Template = segment.writer.Template()
477		}
478	
479		text, err := template.Render(segment.Template, segment.writer)
480		if err != nil {
481			return err.Error()
482		}
483	
484		return text
485	}
486	
487	func (segment *Segment) shouldIncludeFolder() bool {
488		if segment.env == nil {
489			return true
490		}
491	
492		cwdIncluded := segment.cwdIncluded()
493		cwdExcluded := segment.cwdExcluded()
494	
495		return cwdIncluded && !cwdExcluded
496	}
497	
498	func (segment *Segment) cwdIncluded() bool {
499		if len(segment.IncludeFolders) == 0 {
500			return true
501		}
502	
503		return segment.env.DirMatchesOneOf(segment.env.Pwd(), segment.IncludeFolders)
504	}
505	
506	func (segment *Segment) cwdExcluded() bool {
507		return segment.env.DirMatchesOneOf(segment.env.Pwd(), segment.ExcludeFolders)
508	}
509	
510	func (segment *Segment) evaluateNeeds() {
511		if segment.needsEvaluated {
512			return
513		}
514	
515		segment.needsEvaluated = true
516	
517		value := segment.Template
518		if value == "" && segment.writer != nil {
519			value = segment.writer.Template()
520		}
521	
522		if len(segment.ForegroundTemplates) != 0 {
523			value += strings.Join(segment.ForegroundTemplates, "")
524		}
525	
526		if len(segment.BackgroundTemplates) != 0 {
527			value += strings.Join(segment.BackgroundTemplates, "")
528		}
529	
530		if len(segment.Templates) != 0 {
531			value += strings.Join(segment.Templates, "")
532		}
533	
534		if !strings.Contains(value, ".Segments.") {
535			return
536		}
537	
538		matches := regex.FindAllNamedRegexMatch(`\.Segments\.(?P<NAME>[a-zA-Z0-9]+)`, value)
539		for _, name := range matches {
540			segmentName := name["NAME"]
541	
542			if len(name) == 0 || slices.Contains(segment.Needs, segmentName) {
543				continue
544			}
545	
546			segment.Needs = append(segment.Needs, segmentName)
547		}
548	}
549	
550	func (segment *Segment) key() any {
551		if segment.Index > 0 {
552			return segment.Index - 1
553		}
554	
555		return segment.Name()
556	}
